import type { RouteConfig } from '../../router.js';
import type { VietnameseDashboardScreen } from './vietnamese-dashboard-screen.component.js';
import type { VietnameseReviewScreen } from './vietnamese-review-screen.component.js';

let vietnameseLoad: Promise<void> | null = null;
const loadVietnamese = (): Promise<void> => {
    vietnameseLoad ??= Promise.all([
        import('./vietnamese-dashboard-screen.component.js'),
        import('./vietnamese-review-screen.component.js'),
    ]).then(() => undefined);
    return vietnameseLoad;
};

export function vietnameseRoutes(): Record<string, RouteConfig> {
    return {
        '/vietnamese': {
            render: async () => {
                await loadVietnamese();
                return document.createElement('vietnamese-dashboard-screen') as VietnameseDashboardScreen;
            },
        },
        '/vietnamese/review': {
            render: async () => {
                await loadVietnamese();
                return document.createElement('vietnamese-review-screen') as VietnameseReviewScreen;
            },
        },
    };
}
