import {
    STATUS_EVENTS,
    createSaveCredentialEvent,
    createClearCredentialEvent,
} from '../../status-events.js';
import type { StatusEvent } from '../../status-events.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="section">
        <div class="section-header">
            <h3 class="section-title">Master Password</h3>
        </div>
        
        <div id="set-view" hidden>
            <div class="status-grid">
                <span class="status-label">Session Status: <span class="status-badge status-badge--active">✓ Set</span></span>
            </div>
            <div class="actions-row">
                <button type="button" class="action-btn action-btn--danger" id="clear-btn">Clear Password</button>
            </div>
        </div>

        <div id="unset-view" hidden>
            <div class="input-group">
                <input type="password" id="password-input" placeholder="Enter password..." autocomplete="off" autocapitalize="off" spellcheck="false">
                <button type="button" class="action-btn action-btn--primary" id="save-btn">Save</button>
            </div>
        </div>
    </div>
`;


export class CredentialSection extends HTMLElement {
    private _hasCredential = false;
    private setView!: HTMLDivElement;
    private unsetView!: HTMLDivElement;
    private input!: HTMLInputElement;
    private clearBtn!: HTMLButtonElement;
    private saveBtn!: HTMLButtonElement;

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.appendChild(template.content.cloneNode(true));

        this.setView = shadow.getElementById('set-view') as HTMLDivElement;
        this.unsetView = shadow.getElementById('unset-view') as HTMLDivElement;
        this.input = shadow.getElementById('password-input') as HTMLInputElement;
        this.clearBtn = shadow.getElementById('clear-btn') as HTMLButtonElement;
        this.saveBtn = shadow.getElementById('save-btn') as HTMLButtonElement;

        this.clearBtn.addEventListener('click', () => {
            this.dispatchEvent(createClearCredentialEvent());
        });

        this.saveBtn.addEventListener('click', () => this.submit());

        this.input.addEventListener('keydown', (e) => {
            if (e.key === 'Enter') {
                this.submit();
            }
        });

        this.render();
    }

    set hasCredential(val: boolean) {
        if (this._hasCredential === val) return;
        this._hasCredential = val;
        this.render();
    }

    private submit() {
        const value = this.input.value.trim();
        if (!value) return;

        this.dispatchEvent(createSaveCredentialEvent(value));
        this.input.value = '';
    }

    private render() {
        this.setView.hidden = !this._hasCredential;
        this.unsetView.hidden = this._hasCredential;
    }
}

customElements.define('credential-status-section', CredentialSection);
