import type { RouteConfig } from '../../router.js';
import type { HealthDashboardScreen } from './health-dashboard-screen.component.js';
import type { HealthDayScreen } from './health-day-screen.component.js';
import type { HealthScannerScreen } from './health-scanner-screen.component.js';
import type { HealthFoodEntryScreen } from './health-food-entry-screen.component.js';
import type { HealthAiEstimateScreen } from './health-ai-estimate-screen.component.js';
import type { HealthNutritionEditScreen } from './health-nutrition-edit-screen.component.js';
import type { HealthActivityEditScreen } from './health-activity-edit-screen.component.js';
import type { HealthMealsScreen } from './health-meals-screen/health-meals-screen.component.js';



export function healthRoutes(): Record<string, RouteConfig> {
    return {
        '/health': {
            render: async () => {
                await import('./health-dashboard-screen.component.js');
                return document.createElement('health-dashboard-screen') as HealthDashboardScreen;
            },
        },
        '/health/scanner': {
            render: async (ctx) => {
                await import('./health-scanner-screen.component.js');
                const screen = document.createElement('health-scanner-screen') as HealthScannerScreen;
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/scanner/:date/:meal': {
            render: async (ctx) => {
                await import('./health-scanner-screen.component.js');
                const screen = document.createElement('health-scanner-screen') as HealthScannerScreen;
                screen.date = decodeURIComponent(ctx.params.date);
                screen.meal = decodeURIComponent(ctx.params.meal);
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/food-entry': {
            render: async (ctx) => {
                await import('./health-food-entry-screen.component.js');
                const screen = document.createElement('health-food-entry-screen') as HealthFoodEntryScreen;
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/food-entry/:date/:meal': {
            render: async (ctx) => {
                await import('./health-food-entry-screen.component.js');
                const screen = document.createElement('health-food-entry-screen') as HealthFoodEntryScreen;
                screen.date = decodeURIComponent(ctx.params.date);
                screen.meal = decodeURIComponent(ctx.params.meal);
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/ai-estimate': {
            render: async (ctx) => {
                await import('./health-ai-estimate-screen.component.js');
                const screen = document.createElement('health-ai-estimate-screen') as HealthAiEstimateScreen;
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/ai-estimate/:date/:meal': {
            render: async (ctx) => {
                await import('./health-ai-estimate-screen.component.js');
                const screen = document.createElement('health-ai-estimate-screen') as HealthAiEstimateScreen;
                screen.date = decodeURIComponent(ctx.params.date);
                screen.meal = decodeURIComponent(ctx.params.meal);
                screen.query = ctx.query;
                return screen;
            },
        },
        '/health/day/:date': {
            render: async (ctx) => {
                await import('./health-day-screen.component.js');
                const screen = document.createElement('health-day-screen') as HealthDayScreen;
                screen.date = decodeURIComponent(ctx.params.date);
                return screen;
            },
        },
        '/health/nutrition/:id': {
            render: async (ctx) => {
                await import('./health-nutrition-edit-screen.component.js');
                const screen = document.createElement('health-nutrition-edit-screen') as HealthNutritionEditScreen;
                screen.entryId = decodeURIComponent(ctx.params.id);
                return screen;
            },
        },
        '/health/activity/:id': {
            render: async (ctx) => {
                await import('./health-activity-edit-screen.component.js');
                const screen = document.createElement('health-activity-edit-screen') as HealthActivityEditScreen;
                screen.entryId = decodeURIComponent(ctx.params.id);
                return screen;
            },
        },
        '/health/meals': {
            render: async (ctx) => {
                await import('./health-meals-screen/health-meals-screen.component.js');
                const screen = document.createElement('health-meals-screen') as HealthMealsScreen;
                screen.query = ctx.query;
                return screen;
            },
        },
    };
}
