import { buildSectionPage } from '../../utils/section-page.utils.js';
import type { RouteConfig } from '../../router.js';

export function extraRoutes(): Record<string, RouteConfig> {
    return {
        '/extra': {
            render: () => {
                const container = document.createElement('div');
                container.className = 'view-section';
                container.id = 'extra-view';
                const page = buildSectionPage(container, 'Extra', 'extra', '/extra');

                const nav = document.createElement('nav');
                nav.className = 'extra-nav';

                const links: Array<{ href: string; label: string }> = [
                    { href: '/goals', label: 'Goals' },
                    { href: '/agenda', label: 'Calendar' },
                    { href: '/settings/notifications', label: 'Notifications' },
                    { href: '/debug', label: 'Debug' },
                ];

                for (const { href, label } of links) {
                    const a = document.createElement('a');
                    a.href = href;
                    a.className = 'extra-nav-link';
                    a.textContent = label;
                    nav.appendChild(a);
                }

                page.content.appendChild(nav);
                return container;
            },
        },
        '/settings/notifications': {
            render: async () => {
                await import('./notification-settings-screen.component.js');
                return document.createElement('notification-settings-screen');
            },
        },
        '/debug': {
            render: async () => {
                await import('./debug-screen/debug-screen.component.js');
                return document.createElement('debug-screen');
            },
        },
    };
}
