import {
    AbstractHealthRoutes,
    AbstractGoalRoutes,
    AbstractSocialRoutes,
    AbstractVietnameseRoutes,
    type GoalRepository,
    type SocialRepository,
    type VietnameseRepository,
    type ApiResponse,
    type HealthRepositories,
} from '@motivation/shared';

export class HealthOfflineRoutes extends AbstractHealthRoutes {
    protected readonly repos: HealthRepositories;

    constructor(repos: HealthRepositories) {
        super();
        this.repos = repos;
    }
}

export class GoalOfflineRoutes extends AbstractGoalRoutes {
    protected readonly repo: GoalRepository;

    constructor(repo: GoalRepository) {
        super();
        this.repo = repo;
    }
}

export class SocialOfflineRoutes extends AbstractSocialRoutes {
    protected readonly repo: SocialRepository;

    constructor(repo: SocialRepository) {
        super();
        this.repo = repo;
    }
}

const unsupportedFsrsService = {
    reviewCard(): never {
        throw new Error('FSRS review is not available in offline mode');
    },
};

export class VietnameseOfflineRoutes extends AbstractVietnameseRoutes {
    protected readonly repo: VietnameseRepository;

    constructor(repo: VietnameseRepository) {
        super({ fsrsService: unsupportedFsrsService });
        this.repo = repo;
    }

    async 'POST /review'(): Promise<ApiResponse> {
        return this.unavailable('Vietnamese review scheduling requires server connection');
    }
}
